mapper.select:


   /*getMenuPermission*/
   SELECT M.MENU_URLX
        , R.SORT_ORDER AS READ_LEVEL
        , W.SORT_ORDER AS WRIT_LEVEL
        , D.SORT_ORDER AS DELT_LEVEL
     FROM TM_MENUXM M
LEFT JOIN TB_CODEXD R
       ON R.COMM_CODE = #{authCode}
      AND R.COMD_CODE = M.READ_AUTH
      AND NVL(R.USEE_YSNO, #{yes}) = #{yes}
LEFT JOIN TB_CODEXD W
       ON W.COMM_CODE = #{authCode}
      AND W.COMD_CODE = M.WRIT_AUTH
      AND NVL(W.USEE_YSNO, #{yes}) = #{yes}
LEFT JOIN TB_CODEXD D
       ON D.COMM_CODE = #{authCode}
      AND D.COMD_CODE = M.DELT_AUTH
      AND NVL(D.USEE_YSNO, #{yes}) = #{yes}
    WHERE M.MENU_URLX = #{menuUrlx}
      AND NVL(M.USEE_YSNO, #{yes}) = #{yes}
      AND ROWNUM = 1



/*getMenuDtl*/
SELECT 
  FROM TM_MENUXM
 WHERE MENU_NUMB = #{menuNumb}
   AND SUBX_NUMB = #{subxNumb}

  /*getSubMenuList*/



  SELECT 
    FROM TM_MENUXM
   WHERE MENU_NUMB = #{menuNumb}
     AND SUBX_NUMB != #{topMenuSubxNumb}
ORDER BY NVL(SORT_ORDR, 9999) DESC

/*getMenuNumb*/

SELECT TO_CHAR(NVL(MAX(TO_NUMBER(MENU_NUMB)), 0) + 1)
  FROM TM_MENUXM
 WHERE SUBX_NUMB = #{topMenuSubxNumb}

/*getSubxNumb*/
SELECT TO_CHAR(NVL(MAX(TO_NUMBER(SUBX_NUMB)), -1) + 1)
  FROM TM_MENUXM
 WHERE MENU_NUMB = #{menuNumb}

mapper.update:
/*uptMenu*/
UPDATE TM_MENUXM
   SET MENU_NAME = #{menuName}
     , MENU_URLX = #{menuUrlx}
     , READ_AUTH = #{readAuth}
     , WRIT_AUTH = #{writAuth}
     , DELT_AUTH = #{deltAuth}
     , SORT_ORDR = #{sortOrdr}
     , USEE_YSNO = #{useeYsno}
     , UPDT_ADMN = #{updtAdmn}
     , UPDT_DATE = SYSTIMESTAMP
 WHERE MENU_NUMB = #{menuNumb}
   AND SUBX_NUMB = #{subxNumb}

mapper.delete:
/*delMenu*/
DELETE FROM TM_MENUXM
 WHERE MENU_NUMB = #{menuNumb}
   AND SUBX_NUMB = #{subxNumb}
